import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation } from '@angular/core';
/**
 * Conteneur Card avec 3 variantes (default / elevated / flat).
 * Composer avec <ori-card-header>, <ori-card-body>, <ori-card-footer> ou contenu libre.
 */
let OriCardComponent = class OriCardComponent {
    constructor() {
        this.variant = 'default';
        this.wrapperClass = '';
    }
    get classes() {
        return [
            'ori-card',
            this.variant !== 'default' ? `ori-card--${this.variant}` : null,
            this.wrapperClass || null,
        ]
            .filter((c) => Boolean(c))
            .join(' ');
    }
    static { this.propDecorators = {
        variant: [{ type: Input }],
        wrapperClass: [{ type: Input }]
    }; }
};
OriCardComponent = __decorate([
    Component({
        selector: 'ori-card',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<ng-content></ng-content>`,
        host: {
            '[class]': 'classes',
        },
    })
], OriCardComponent);
export { OriCardComponent };
let OriCardHeaderComponent = class OriCardHeaderComponent {
    constructor() {
        this.title = '';
        this.subtitle = '';
    }
    static { this.propDecorators = {
        title: [{ type: Input }],
        subtitle: [{ type: Input }]
    }; }
};
OriCardHeaderComponent = __decorate([
    Component({
        selector: 'ori-card-header',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    @if (title) {
      <h3 class="ori-card__title">{{ title }}</h3>
    }
    @if (subtitle) {
      <p class="ori-card__subtitle">{{ subtitle }}</p>
    }
    <ng-content></ng-content>
  `,
        host: { class: 'ori-card__header' },
    })
], OriCardHeaderComponent);
export { OriCardHeaderComponent };
let OriCardBodyComponent = class OriCardBodyComponent {
};
OriCardBodyComponent = __decorate([
    Component({
        selector: 'ori-card-body',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<ng-content></ng-content>`,
        host: { class: 'ori-card__body' },
    })
], OriCardBodyComponent);
export { OriCardBodyComponent };
let OriCardFooterComponent = class OriCardFooterComponent {
};
OriCardFooterComponent = __decorate([
    Component({
        selector: 'ori-card-footer',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<ng-content></ng-content>`,
        host: { class: 'ori-card__footer' },
    })
], OriCardFooterComponent);
export { OriCardFooterComponent };
